    return {
      fetchedAt,
      sessionId,
      currency: 'USD',
      rates: Object.fromEntries(
        Object.entries(rates).map(([k, v]) => [k, parseFloat(v as string) || 0])
      ),
      bitcoin: {
        usd: 1 / bitcoinUsd, // Inverse because API gives USD per BTC
        change24h: null, // Requires historical comparison
      },
      ethereum: {
        usd: 1 / ethereumUsd,
        change24h: null,
      },
    };
